text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "decisions": {
      "confirmed_decisions": [
        {
          "topic": "공개 릴리스 목표 시점",
          "decision": "스모크 테스트 통과 시 금요일 15:00 KST를 공개 릴리스 목표로 한다.",
          "conditions": [
            "스모크 테스트가 통과해야 한다."
          ],
          "source_certainty": "confirmed"
        },
        {
          "topic": "packageName mismatch 대응",
          "decision": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
          "source_certainty": "confirmed"
        }
      ],
      "rejected_proposals": [
        {
          "topic": "smoke-theme-pack.mjs 처리 방식",
          "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경하자.",
          "result": "rejected",
          "source_certainty": "confirmed"
        }
      ],
      "internal_stretch_goals": [
        {
          "topic": "수요일 릴리스 제안",
          "detail": "수요일 릴리스는 내부 스트레치 골일 뿐이며 확정 일정이 아니다.",
          "source_certainty": "confirmed"
        }
      ]
    },
    "non_decisions": {
      "not_confirmed": [
        {
          "topic": "README 설치 절차 검토",
          "detail": "목요일까지 검토하면 좋다는 의견은 있었지만, 담당자 배정은 없었다.",
          "source_certainty": "confirmed"
        },
        {
          "topic": "Hara의 타르볼 경로 확인 시점",
          "detail": "Minjun의 스모크 결과 공유 이후 확인하기로 했으나 정확한 마감 시각은 정해지지 않았다.",
          "source_certainty": "confirmed"
        }
      ]
    },
    "risks": [
      {
        "risk": "잘못된 타르볼 경로는 릴리스를 지연시킬 수 있다.",
        "source_certainty": "confirmed"
      },
      {
        "risk": "README 설치 절차가 오래되었으면 릴리스 노트가 사용자를 오도할 수 있다.",
        "source_certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "open",
        "source_certainty": "confirmed"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 골을 언급해야 하는가?",
        "status": "open",
        "source_certainty": "confirmed"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": "목요일 가능 시",
      "status": "미배정",
      "source_certainty": "partial"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 타르볼 경로를 확인한다.",
      "due": "미정",
      "status": "확정",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 스모크 테스트 재실행 결과가 금요일 10:00 KST까지 공유되었는지 확인",
      "Doyun의 실패 트리아지 노트가 금요일 12:00 KST까지 action_items.md에 반영되었는지 확인",
      "스모크 통과 여부를 기준으로 금요일 15:00 KST 공개 릴리스 조건이 충족되는지 점검",
      "타르볼 경로가 올바른지 Hara의 확인 결과를 점검",
      "README 설치 절차 검토의 담당자 지정 여부와 실제 검토 완료 여부를 확인",
      "최종 릴리스 승인 권한자와 릴리스 노트의 수요일 스트레치 골 언급 여부를 후속 결정 항목으로 유지"
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요 여부",
      "미지정 담당자",
      "명시되지 않은 마감시한",
      "확정되지 않은 승인 권한자"
    ]
  },
  "non_invention_rules": [
    "인라인 픽스처에 없는 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "담당자가 명시되지 않은 작업에 임의로 owner를 부여하지 않는다.",
    "정해지지 않은 마감시한을 추정해 확정값처럼 쓰지 않는다.",
    "거절된 제안과 확정된 결정을 혼합하지 않는다.",
    "내부 스트레치 골을 확정 일정이나 대외 약속처럼 쓰지 않는다.",
    "오픈 질문을 이미 해결된 사실처럼 쓰지 않는다."
  ]
}
